/**
 * 工具箱注册表 —— 工具箱信息架构的单一数据源
 *
 * 设计见 .kiro/specs/toolbox-reorganization/design.md
 * 所有导航（分组首页、详情容器）均由本注册表驱动。
 */
import { defineAsyncComponent, type Component } from 'vue';

/** 4 个工具分组键 */
export type ToolGroupKey = 'authoring' | 'worldbook' | 'optimize' | 'frontend';

/** 工具唯一 id（沿用旧的展开 key，保证持久化向后兼容） */
export type ToolId =
  | 'cardAgent'
  | 'npcGen'
  | 'characterCard'
  | 'greetingGen'
  | 'worldbookEntry'
  | 'worldbookViewer'
  | 'tokenCompress'
  | 'relationMap'
  | 'uiGenerator';

export interface ToolDefinition {
  id: ToolId;
  /** 显示名称的 i18n key，无则回退到 label */
  i18nKey?: string;
  /** 回退显示名称 */
  label: string;
  /** 一句话简述（首页工具行副标题） */
  desc: string;
  /** FontAwesome 图标类 */
  icon: string;
  /** 主题强调色（iOS 风格） */
  color: string;
  /** 所属分组 */
  group: ToolGroupKey;
  /** 详情页渲染的组件（懒加载） */
  component: Component;
  /** 搜索关键词（中英文别名） */
  keywords: string[];
  /** 排序权重，越小越靠前 */
  order: number;
}

export interface ToolGroup {
  key: ToolGroupKey;
  label: string;
  icon: string;
  color: string;
  tools: ToolDefinition[];
}

