/**
 * 按分组聚合工具。
 * - 返回顺序固定为 authoring → worldbook → optimize → frontend
 * - 每组内按 order 升序
 * - 空分组不返回
 */
export function buildToolGroups(registry: ToolDefinition[] = toolRegistry): ToolGroup[] {
  const result: ToolGroup[] = [];
  for (const key of GROUP_ORDER) {
    const tools = registry
      .filter(t => t.group === key)
      .sort((a, b) => a.order - b.order);
    if (tools.length > 0) {
      result.push({ ...groupMeta[key], tools });
    }
  }
  return result;
}

/**
 * 按分组过滤 + 关键词搜索（纯函数，不改输入）。
 * - activeGroup !== 'all' 时只保留该分组
 * - query 非空时按 名称/简述/关键词 大小写不敏感子串匹配
 * - 过滤后为空的分组不返回
 */
export function filterTools(
  groups: ToolGroup[],
  activeGroup: ToolGroupKey | 'all',
  query: string,
): ToolGroup[] {
  const q = (query || '').trim().toLowerCase();
  const result: ToolGroup[] = [];

  for (const group of groups) {
    if (activeGroup !== 'all' && group.key !== activeGroup) continue;

    const tools = q
      ? group.tools.filter(t => {
          const haystack = [t.label, t.desc, ...t.keywords].join(' ').toLowerCase();
          return haystack.includes(q);
        })
      : group.tools;

    if (tools.length > 0) {
      result.push({ ...group, tools });
    }
  }
  return result;
}

/** 根据 id 解析工具组件；未知 id 返回 null（调用方回退首页，避免白屏） */
export function resolveToolComponent(id: string): Component | null {
  const def = toolRegistry.find(t => t.id === id);
  return def ? def.component : null;
}

/** 根据 id 取工具定义 */
export function getToolDefinition(id: string): ToolDefinition | null {
  return toolRegistry.find(t => t.id === id) || null;
}
