<template>
  <div style="font-family: -apple-system, BlinkMacSystemFont, 'SF Pro Text', 'PingFang SC', 'Microsoft YaHei', sans-serif">
    <!-- 搜索框 -->
    <div style="position: relative; margin-bottom: 14px">
      <i
        class="fa-solid fa-magnifying-glass"
        style="position: absolute; left: 14px; top: 50%; transform: translateY(-50%); color: rgba(235,235,245,0.4); font-size: 13px"
      ></i>
      <input
        :value="searchQuery"
        type="text"
        placeholder="搜索工具…"
        style="
          width: 100%;
          box-sizing: border-box;
          padding: 11px 36px;
          background: rgba(255,255,255,0.08);
          border: 0.5px solid rgba(255,255,255,0.1);
          border-radius: 12px;
          color: #f5f5f7;
          font-size: 14px;
          outline: none;
          font-family: inherit;
        "
        @input="$emit('update:searchQuery', ($event.target as HTMLInputElement).value)"
      />
      <i
        v-if="searchQuery"
        class="fa-solid fa-circle-xmark"
        style="position: absolute; right: 12px; top: 50%; transform: translateY(-50%); color: rgba(235,235,245,0.4); font-size: 14px; cursor: pointer"
        @click="$emit('update:searchQuery', '')"
      ></i>
    </div>

    <!-- 分组分段控件 -->
    <div style="display: flex; gap: 6px; flex-wrap: wrap; margin-bottom: 18px">
      <button
        v-for="seg in segments"
        :key="seg.key"
        :style="segStyle(seg.key === activeGroup)"
        @click="$emit('update:activeGroup', seg.key)"
      >
        <i v-if="seg.icon" :class="seg.icon" style="margin-right: 5px; font-size: 11px"></i>{{ seg.label }}
      </button>
    </div>

    <!-- 分组卡片 -->
    <div v-if="visibleGroups.length > 0" style="display: flex; flex-direction: column; gap: 16px">
      <section
        v-for="group in visibleGroups"
        :key="group.key"
        style="border-radius: 16px; background: rgba(44,44,46,0.55); border: 0.5px solid rgba(255,255,255,0.08); overflow: hidden"
      >
        <div style="display: flex; align-items: center; gap: 8px; padding: 13px 16px 9px; color: rgba(235,235,245,0.6); font-size: 12.5px; font-weight: 600; letter-spacing: 0.3px">
          <i :class="group.icon" :style="{ color: group.color, fontSize: '13px' }"></i>
          {{ group.label }}
        </div>
        <div style="padding: 0 10px 8px">
          <button
            v-for="(tool, idx) in group.tools"
            :key="tool.id"
            :style="rowStyle(idx)"
            @click="$emit('select-tool', tool.id)"
          >
            <span
              :style="{
                flex: '0 0 auto',
                width: '34px',
                height: '34px',
                borderRadius: '9px',
                display: 'inline-flex',
                alignItems: 'center',
                justifyContent: 'center',
                background: tool.color + '22',
                color: tool.color,
                fontSize: '15px',
              }"
            >
              <i :class="tool.icon"></i>
            </span>
            <span style="flex: 1; min-width: 0; text-align: left">
              <span style="display: block; color: #f5f5f7; font-size: 14.5px; font-weight: 500">{{ displayName(tool) }}</span>
              <span style="display: block; color: rgba(235,235,245,0.5); font-size: 12px; margin-top: 2px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap">{{ tool.desc }}</span>
            </span>
            <i class="fa-solid fa-chevron-right" style="color: rgba(235,235,245,0.35); font-size: 12px"></i>
          </button>
        </div>
      </section>
    </div>

    <!-- 空状态 -->
    <div v-else style="text-align: center; padding: 50px 20px; color: rgba(235,235,245,0.45)">
      <i class="fa-solid fa-magnifying-glass" style="font-size: 40px; margin-bottom: 14px; color: rgba(235,235,245,0.18)"></i>
      <div style="color: rgba(235,235,245,0.7); font-weight: 500">没有匹配的工具</div>
      <div style="font-size: 12px; margin-top: 6px">换个关键词或切换分组试试</div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { computed } from 'vue';
import { useI18n } from '../../i18n';
import { filterTools, type ToolDefinition, type ToolGroup, type ToolGroupKey } from './toolRegistry';

const props = defineProps<{
  groups: ToolGroup[];
  activeGroup: ToolGroupKey | 'all';
  searchQuery: string;
}>();

defineEmits<{
  (e: 'select-tool', id: string): void;
  (e: 'update:activeGroup', key: ToolGroupKey | 'all'): void;
  (e: 'update:searchQuery', q: string): void;
}>();

const { t } = useI18n();

const segments = computed(() => [
  { key: 'all' as const, label: '全部', icon: '' },
  ...props.groups.map(g => ({ key: g.key, label: g.label, icon: g.icon })),
]);

const visibleGroups = computed(() => filterTools(props.groups, props.activeGroup, props.searchQuery));

function displayName(tool: ToolDefinition): string {
  if (tool.i18nKey) {
    const translated = t(tool.i18nKey);
    if (translated && translated !== tool.i18nKey) return translated;
  }
  return tool.label;
}

function segStyle(active: boolean): string {
  return `padding: 7px 14px; border: none; border-radius: 999px; cursor: pointer; font-size: 12.5px; font-weight: 600; font-family: inherit; background: ${active ? '#0a84ff' : 'rgba(255,255,255,0.08)'}; color: ${active ? '#fff' : 'rgba(235,235,245,0.8)'};`;
}

function rowStyle(idx: number): string {
  const border = idx === 0 ? '' : 'border-top: 0.5px solid rgba(255,255,255,0.06);';
  return `width: 100%; box-sizing: border-box; display: flex; align-items: center; gap: 12px; padding: 11px 6px; background: transparent; border: none; cursor: pointer; ${border}`;
}
</script>
