<script setup lang="ts">
import { computed, ref } from 'vue';
import { useI18n } from '../i18n';
import { type SummaryHistoryItem, useSummaryHistoryStore, useSettingsStore } from '../settings';
import type { VisualSummary } from '../types/visual-summary';
import { getChatIdSafe, getScriptIdSafe } from '../utils';
import {
  formatVisualSummaryAsMarkdown,
  formatVisualSummaryForHistory,
  parseVisualSummary,
} from '../utils/visual-summary-format';
import { resolveSummaryWorldbookName } from '../utils/summary-worldbook';
import { runMegaSummary } from '../utils/mega-summary';
import QuickGuide from './QuickGuide.vue';
import VisualSummaryDialog from './VisualSummaryDialog.vue';
import VisualSummaryPanel from './VisualSummaryPanel.vue';

// 国际化
const { t } = useI18n();

const historyStore = useSummaryHistoryStore();
const settingsStore = useSettingsStore();

// 兼容性辅助函数：优先使用新 API，回退到旧 API
const getWorldbookNamesCompat = (): string[] => {
  const tav = (window as any).TavernHelper;
  if (typeof tav?.getWorldbookNames === 'function') {
    return tav.getWorldbookNames();
  }
  if (typeof tav?.getLorebooks === 'function') {
    return tav.getLorebooks();
  }
  throw new Error('无法获取世界书列表，请更新 SillyTavern 到最新版本');
};

const getHostDocument = (): Document => {
  try {
    if (window.parent && window.parent !== window) {
      return window.parent.document;
    }
  } catch {
    // ignore cross-origin access errors
  }
  return document;
};

const escapeHtml = (value: string): string =>
  String(value)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');

// 响应式数据
const summary_history = ref<SummaryHistoryItem[]>([]);
const expandedState = ref<Map<number, boolean>>(new Map());
const isMegaSummarizing = ref(false);
const isTidying = ref(false);

// 记忆状态概览（粗略估算，token 按「字符数 / 1.5」近似中文 token）
const memoryStats = computed(() => {
  const list = summary_history.value || [];
  const total = list.length;
  const megaCount = list.filter(s => String(s.content || '').includes('【大总结】')).length;
  let maxFloor = 0;
  let chars = 0;
  for (const s of list) {
    if ((s.end_id ?? 0) > maxFloor) maxFloor = s.end_id ?? 0;
    chars += String(s.content || '').length;
  }
  const approxTokens = chars > 0 ? Math.round(chars / 1.5).toLocaleString() : '0';
  return { total, megaCount, maxFloor, approxTokens };
});
const showVisualSummaryDialog = ref(false);
const visualSummaryDraft = ref<VisualSummary | null>(null);

// 更新总结历史的函数
const refreshSummaryHistory = () => {
  try {
    summary_history.value = historyStore.getSummaryHistory();
    console.log('已刷新总结历史，当前聊天记录数:', summary_history.value.length);
  } catch (e) {
    console.error('刷新总结历史失败:', e);
    summary_history.value = [];
  }
};

// 切换展开状态
const toggleExpanded = (index: number) => {
  const current = expandedState.value.get(index) || false;
  expandedState.value.set(index, !current);
};

const isExpanded = (index: number) => {
  return expandedState.value.get(index) || false;
};

// 处理刷新数据按钮
const handleRefreshData = async () => {
  console.log('刷新数据按钮被点击');
  try {
    await refreshSummaryHistory();
    window.toastr.success('数据已刷新');
  } catch (error) {
    console.error('刷新数据失败:', error);
    window.toastr.error('刷新数据失败: ' + (error as Error).message);
  }
};

const saveVisualSummary = (summary: VisualSummary) => {
  historyStore.addSummary(
    summary.range.start,
    summary.range.end,
    formatVisualSummaryForHistory(summary),
    JSON.parse(JSON.stringify(summary)),
  );
  refreshSummaryHistory();
  showVisualSummaryDialog.value = false;
  window.toastr.success('可视化总结已保存到历史');
};

const copyVisualSummaryJson = async (summary: VisualSummary) => {
  await copyToClipboard(JSON.stringify(summary, null, 2), '可视化总结 JSON 已复制');
};

const copyVisualSummaryMarkdown = async (summary: unknown) => {
  const parsed = parseVisualSummary(summary);
  if (!parsed) {
    window.toastr.error('可视化总结数据无效，无法复制 Markdown');
    return;
  }
  await copyToClipboard(formatVisualSummaryAsMarkdown(parsed), '可视化总结 Markdown 已复制');
};

const editVisualSummary = (summary: unknown) => {
  const parsed = parseVisualSummary(summary);
  if (!parsed) {
    window.toastr.error('可视化总结数据无效，无法继续编辑');
    return;
  }
  visualSummaryDraft.value = parsed;
  showVisualSummaryDialog.value = true;
};

const generateWorldbookCandidates = (summary: VisualSummary) => {
  const existingKeys = new Set(
    summary.worldbookCandidates.map(item => `${item.type}:${item.title}`.toLowerCase()),
  );
  const candidates: VisualSummary['worldbookCandidates'] = [];

  for (const character of summary.characters) {
    if (!character.name) continue;
    const key = `character:${character.name}`.toLowerCase();
    if (existingKeys.has(key)) continue;
    candidates.push({
      type: 'character',
      title: character.name,
      content: [
        `角色：${character.name}`,
        `当前状态：${character.status || '未记录'}`,
        `态度变化：${character.attitude || '未记录'}`,
        `应记忆内容：${character.memory || '未记录'}`,
      ].join('\n'),
      enabled: true,
    });
  }

  if (summary.location) {
    const key = `location:${summary.location}`.toLowerCase();
    if (!existingKeys.has(key)) {
      candidates.push({
        type: 'location',
        title: summary.location,
        content: `地点：${summary.location}\n相关剧情：${summary.overview || '未记录'}`,
        enabled: true,
      });
    }
  }

  if (summary.foreshadowing.length) {
    const key = `plot:${summary.title}-伏笔`.toLowerCase();
    if (!existingKeys.has(key)) {
      candidates.push({
        type: 'plot',
        title: `${summary.title || `楼层${summary.range.start}-${summary.range.end}`}-伏笔`,
        content: summary.foreshadowing.map(item => `- ${item}`).join('\n'),
        enabled: true,
      });
    }
  }

  summary.worldbookCandidates.push(...candidates);
  window.toastr.success(`已补充 ${candidates.length} 条世界书候选`);
};

const writeVisualSummaryToWorldbook = async (summary: VisualSummary) => {
  try {
    const enabledCandidates = summary.worldbookCandidates.filter(item => item.enabled && item.title && item.content);
    if (enabledCandidates.length === 0) {
      window.toastr.warning('没有勾选且内容完整的世界书候选');
      return;
    }

    if (typeof (window as any).TavernHelper === 'undefined') {
      window.toastr.error('TavernHelper 不可用，请确保在 SillyTavern 环境中运行');
      return;
    }

    const worldbookNames = getWorldbookNamesCompat();
    const selectedWorldbook =
      worldbookNames.length === 1 ? worldbookNames[0] : await promptForWorldbook(worldbookNames);
    if (!selectedWorldbook) return;

    const entries = enabledCandidates.map((candidate, index) => ({
      name: candidate.title || `可视化总结_${index + 1}`,
      enabled: true,
      strategy: {
        type: 'constant' as const,
        keys: [],
        keys_secondary: { logic: 'and_any' as const, keys: [] },
        scan_depth: 'same_as_global' as const,
      },
      position: {
        type: 'before_character_definition' as const,
        role: 'system' as const,
        depth: 1,
      },
      content: candidate.content,
      comment: `可视化总结候选 - ${candidate.type} - 楼层 ${summary.range.start}-${summary.range.end}`,
      insertion_order: index,
      // 默认勾选：不可被其他条目递归激活 + 禁止本条目递归激活其他条目
      recursion: {
        prevent_incoming: true,
        prevent_outgoing: true,
        delay_until: null,
      },
      uid: Date.now() + index,
    }));

    await (window as any).TavernHelper.createWorldbookEntries(selectedWorldbook, entries, { render: 'immediate' });
    window.toastr.success(`已写入 ${entries.length} 条世界书候选到 ${selectedWorldbook}`);
  } catch (error) {
    console.error('写入可视化总结世界书失败:', error);
    window.toastr.error('写入世界书失败: ' + (error as Error).message);
  }
};

// 处理大总结：将多个小总结合并成一个可视化大总结，绑定世界书，并关闭对应小总结条目
const handleMegaSummary = async () => {
  if (summary_history.value.length < 2) {
    window.toastr.warning('需要至少 2 条小总结才能生成大总结');
    return;
  }

  isMegaSummarizing.value = true;
  try {
    console.log('🔄 开始生成可视化大总结...');
    window.toastr.info('正在生成大总结...');

    const result = await runMegaSummary(summary_history.value);
    if (!result) {
      window.toastr.warning('需要至少 2 条小总结才能生成大总结');
      return;
    }
    refreshSummaryHistory();
    window.toastr.success(`大总结已生成（合并 ${result.mergedCount} 条小总结）`);
    console.log('✅ 大总结完成:', result.visual);
  } catch (error) {
    console.error('❌ 生成大总结失败:', error);
    window.toastr.error('生成大总结失败: ' + (error as Error).message);
  } finally {
    isMegaSummarizing.value = false;
  }
};

// 一键整理记忆：智能召回平衡（旧总结转绿灯）+ 合并大总结 + 清理无对应聊天的孤儿世界书
const handleTidyMemory = async () => {
  if (isTidying.value) return;
  isTidying.value = true;
  const done: string[] = [];
  try {
    window.toastr.info('开始整理记忆，请稍候...');
    const TH = (window as any).TavernHelper;

    // 1) 智能召回平衡：把较早的总结转绿灯关键词召回，只留最近 N 条常驻
    try {
      const { rebalanceSummaryRecall } = await import('../utils/smart-recall');
      const { resolveSummaryWorldbookName } = await import('../utils/summary-worldbook');
      const wb = resolveSummaryWorldbookName().name;
      const keep = settingsStore.settings.smart_recall_keep_recent ?? 1;
      if (TH && wb) {
        await rebalanceSummaryRecall(TH, wb, keep);
        done.push('智能召回平衡');
      }
    } catch (e) {
      console.warn('智能召回平衡失败（忽略）:', e);
    }

    // 2) 合并大总结（小总结 >= 2 时）
    try {
      const smalls = summary_history.value.filter(s => !String(s.content || '').includes('【大总结】'));
      if (smalls.length >= 2) {
        const result = await runMegaSummary(summary_history.value);
        if (result) {
          refreshSummaryHistory();
          done.push(`合并大总结（${result.mergedCount} 条）`);
        }
      }
    } catch (e) {
      console.warn('合并大总结失败（忽略）:', e);
    }

    // 3) 清理无对应聊天的孤儿总结世界书
    try {
      const { cleanupOrphanSummaryWorldbooks } = await import('../utils/summary-worldbook');
      const deleted = await cleanupOrphanSummaryWorldbooks();
      if (deleted.length > 0) done.push(`清理 ${deleted.length} 本残留世界书`);
    } catch (e) {
      console.warn('清理孤儿世界书失败（忽略）:', e);
    }

    window.toastr.success(done.length ? `记忆整理完成：${done.join('、')}` : '记忆已是整理好的状态');
  } catch (error) {
    console.error('❌ 一键整理记忆失败:', error);
    window.toastr.error('整理记忆失败: ' + (error as Error).message);
  } finally {
    isTidying.value = false;
  }
};

// 统一的复制函数 - 针对iframe环境优化
const copyToClipboard = async (text: string, successMessage: string = '内容已复制到剪贴板') => {
  console.log('开始复制，文本长度:', text.length);

  try {
    // 在iframe环境中，优先尝试在父窗口中复制
    if (window.parent && window.parent !== window) {
      console.log('检测到iframe环境，尝试在父窗口复制');
      const parentSuccess = await tryParentWindowCopy(text);
      if (parentSuccess) {
        console.log('父窗口复制成功');
        window.toastr.success(successMessage);
        return;
      }
    }

    // 方法1: 尝试使用现代的 Clipboard API（仅在安全上下文中）
    if (navigator.clipboard && window.isSecureContext) {
      console.log('使用现代 Clipboard API');
      try {
        await navigator.clipboard.writeText(text);
        console.log('Clipboard API 复制成功');
        window.toastr.success(successMessage);
        return;
      } catch (clipboardErr) {
        console.warn('Clipboard API 失败:', clipboardErr);
        // 继续尝试其他方法
      }
    }

    // 方法2: 使用传统的 execCommand 方法
    console.log('使用 execCommand 方法');
    const success = await execCommandCopy(text);
    if (success) {
      console.log('execCommand 复制成功');
      window.toastr.success(successMessage);
      return;
    }

    // 方法3: 如果都失败了，显示文本框让用户手动复制
    console.log('所有自动复制方法都失败，显示手动复制界面');
    showManualCopyDialog(text);
  } catch (err) {
    console.error('复制异常:', err);
    // 出错时也显示手动复制界面
    showManualCopyDialog(text);
  }
};

// 在父窗口中尝试复制
const tryParentWindowCopy = async (text: string): Promise<boolean> => {
  return new Promise(resolve => {
    try {
      const parentDoc = window.parent.document;
      const parentBody = window.parent.document.body;

      // 创建一个临时的 textarea 元素在父窗口中
      const textarea = parentDoc.createElement('textarea');
      textarea.value = text;
      textarea.style.cssText = `
        position: fixed;
        left: -9999px;
        top: -9999px;
        opacity: 0;
        pointer-events: none;
        z-index: -1000;
      `;
      textarea.setAttribute('readonly', '');

      parentBody.appendChild(textarea);

      // 选中文本
      textarea.focus();
      textarea.select();
      textarea.setSelectionRange(0, text.length);

      // 尝试复制
      const success = parentDoc.execCommand('copy');

      // 清理
      parentBody.removeChild(textarea);

      resolve(success);
    } catch (err) {
      console.error('父窗口复制失败:', err);
      resolve(false);
    }
  });
};

// execCommand 复制方法
const execCommandCopy = async (text: string): Promise<boolean> => {
  return new Promise(resolve => {
    try {
      // 创建一个临时的 textarea 元素
      const textarea = document.createElement('textarea');
      textarea.value = text;
      textarea.style.position = 'fixed';
      textarea.style.left = '-9999px';
      textarea.style.top = '-9999px';
      textarea.style.opacity = '0';
      textarea.style.pointerEvents = 'none';
      textarea.setAttribute('readonly', '');

      document.body.appendChild(textarea);

      // 选中文本
      textarea.select();
      textarea.setSelectionRange(0, text.length);

      // 尝试复制
      const success = document.execCommand('copy');

      // 清理
      document.body.removeChild(textarea);

      resolve(success);
    } catch (err) {
      console.error('execCommand 复制失败:', err);
      resolve(false);
    }
  });
};

