// 删除总结（插件环境 - 使用 localStorage）
const deleteSummary = async (index: number) => {
  if (confirm('确定要删除这条总结吗？\n（如果该总结已自动绑定到世界书，对应的世界书条目也会一并删除）')) {
    try {
      const chat_id = getChatIdSafe();
      if (!chat_id) {
        window.toastr.error('无法获取当前聊天信息');
        return;
      }

      // 先记录该总结的楼层范围，用于删除对应的世界书条目
      const target = summary_history.value[index];
      const startId = target?.start_id;
      const endId = target?.end_id;

      summary_history.value.splice(index, 1);

      // 保存到 localStorage（按聊天ID存储）
      const scriptId = getScriptIdSafe();
      const storageKey = `${scriptId}_summary_history_${chat_id}`;
      localStorage.setItem(storageKey, JSON.stringify(summary_history.value));
      console.log('✅ 总结已删除并保存到 localStorage');

      // 同步删除插件创建的世界书条目（尽力而为，不阻断历史删除）
      if (startId != null && endId != null) {
        await deleteSummaryWorldbookEntry(startId, endId);
      }

      window.toastr.success('总结已删除');
    } catch (error) {
      console.error('删除总结失败:', error);
      window.toastr.error('删除总结失败');
    }
  }
};

// 删除插件为该总结自动创建的世界书条目（条目名 总结_楼层X-Y 或 comment 含 楼层范围: X - Y）
const deleteSummaryWorldbookEntry = async (startId: number, endId: number) => {
  try {
    const TH = (window as any).TavernHelper;
    if (!TH || typeof TH.deleteWorldbookEntries !== 'function') return;

    const entryName = `总结_楼层${startId}-${endId}`;
    // 只匹配插件自己创建的总结条目（名字固定为 总结_楼层X-Y，且 comment 标记为自动生成）
    const matcher = (entry: any) =>
      (entry?.name === entryName && entry?.comment?.includes('自动生成的总结条目')) ||
      (entry?.name === entryName && entry?.comment?.includes(`楼层范围: ${startId} - ${endId}`));

    // 🔒 安全：只在「当前聊天绑定的世界书」和「插件稳定命名的总结世界书」里删，
    // 绝不碰角色卡的附加知识书（避免误删用户自己挂的其他世界书条目）。
    const candidates = new Set<string>();
    try {
      const chatWb = TH.getChatWorldbookName?.('current');
      if (chatWb) candidates.add(chatWb);
    } catch {
      /* ignore */
    }
    // 插件稳定命名：总结_角色_chatId
    try {
      let characterName = '未知角色';
      const currentCharacter = TH.getCharData?.('current');
      if (currentCharacter?.name) {
        characterName = currentCharacter.name.replace(/[<>:"/\\|?*]/g, '_').trim();
      }
      const chatId = getChatIdSafe() || 'default';
      const shortChatId = chatId.length > 8 ? chatId.slice(-8) : chatId;
      candidates.add(`总结_${characterName}_${shortChatId}`);
    } catch {
      /* ignore */
    }

    let deleted = false;
    for (const wbName of candidates) {
      if (!wbName) continue;
      try {
        await TH.deleteWorldbookEntries(wbName, matcher);
        deleted = true;
      } catch (e) {
        // 单本失败忽略（世界书可能不存在或无该条目）
        console.warn(`删除世界书「${wbName}」中的总结条目失败:`, e);
      }
    }
    if (deleted) {
      console.log(`✅ 已尝试删除世界书中的总结条目: ${entryName}`);
    }
  } catch (e) {
    console.warn('删除总结对应的世界书条目失败（忽略）:', e);
  }
};

// 导出全部总结
const exportAllSummaries = () => {
  try {
    if (summary_history.value.length === 0) {
      window.toastr.warning('没有可导出的总结记录');
      return;
    }

    // 获取角色名
    let characterName = '未知角色';
    try {
      const currentCharacter = (window as any).TavernHelper?.getCharData?.('current');
      if (currentCharacter?.name) {
        characterName = currentCharacter.name.replace(/[<>:"/\\|?*]/g, '_').trim();
      }
    } catch (e) {
      console.warn('获取角色信息失败:', e);
    }

    // 构建导出内容
    const exportData = {
      exportTime: new Date().toISOString(),
      characterName,
      totalCount: summary_history.value.length,
      summaries: summary_history.value.map((item, index) => ({
        index: index + 1,
        startFloor: item.start_id,
        endFloor: item.end_id,
        content: item.content,
      })),
    };

    // 下载为 JSON 文件
    const blob = new Blob([JSON.stringify(exportData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `总结记录_${characterName}_${new Date().toLocaleDateString('zh-CN').replace(/\//g, '-')}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);

    window.toastr.success(`已导出 ${summary_history.value.length} 条总结记录`);
  } catch (error) {
    console.error('导出总结失败:', error);
    window.toastr.error('导出失败');
  }
};

