// 创建总结世界书
const createSummaryWorldbook = async () => {
  try {
    // 检查 TavernHelper 是否可用
    if (typeof (window as any).TavernHelper === 'undefined') {
      window.toastr.error('TavernHelper 不可用，请确保在 SillyTavern 环境中运行');
      return;
    }

    // 🔧 统一命名：优先复用当前聊天已绑定的世界书，否则用稳定名（同一聊天永远同名），
    // 避免之前「日期命名 / 聊天ID命名」两套规则导致同一聊天反复创建多本世界书。
    const resolved = resolveSummaryWorldbookName();
    if (resolved.isBound) {
      window.toastr.info(`当前聊天已绑定世界书「${resolved.name}」，无需重复创建`);
      return;
    }

    const worldbookName = resolved.name;
    const existingWorldbooks = getWorldbookNamesCompat();
    if (existingWorldbooks.includes(worldbookName)) {
      // 已存在同名，直接绑定即可，不再新建
      try {
        await (window as any).TavernHelper.rebindChatWorldbook('current', worldbookName);
        window.toastr.success(`已绑定已存在的总结世界书「${worldbookName}」到当前聊天`);
      } catch (bindError) {
        console.warn('绑定到聊天失败:', bindError);
        window.toastr.warning(`世界书「${worldbookName}」已存在，请手动在聊天知识书中绑定`);
      }
      return;
    }

    console.log('准备创建世界书:', worldbookName);
    await (window as any).TavernHelper.createWorldbook(worldbookName, []);

    try {
      await (window as any).TavernHelper.rebindChatWorldbook('current', worldbookName);
      window.toastr.success(`已创建总结世界书 "${worldbookName}" 并绑定到当前聊天`);
    } catch (bindError) {
      console.warn('绑定到聊天失败:', bindError);
      window.toastr.success(`已创建总结世界书 "${worldbookName}"，请手动在聊天知识书中绑定`);
    }
  } catch (error) {
    console.error('创建总结世界书失败:', error);
    window.toastr.error('创建总结世界书失败: ' + (error as Error).message);
  }
};

