// 让用户选择世界书的辅助函数
const promptForWorldbook = async (worldbookNames: string[]): Promise<string | null> => {
  return new Promise<string | null>(resolve => {
    const hostDocument = getHostDocument();
    const hostBody = $(hostDocument.body);
    const zIndex = 2147483647;
    const dialogId = `maomaomz-worldbook-dialog-${Date.now()}`;
    const overlayId = `${dialogId}-overlay`;

    const dialog = $(`
      <div id="${dialogId}" style="
        position: fixed;
        top: 50%;
        left: 50%;
        transform: translate(-50%, -50%);
        background: #2a3a4a;
        border: 1px solid rgba(84, 107, 131, 0.3);
        border-radius: 8px;
        padding: 20px;
        z-index: ${zIndex};
        min-width: 300px;
        max-width: min(420px, calc(100vw - 32px));
        box-shadow: 0 16px 48px rgba(0, 0, 0, 0.55);
      ">
        <h3 style="margin: 0 0 15px 0; color: #e0e0e0;">选择世界书</h3>
        <div style="margin-bottom: 15px; max-height: 300px; overflow-y: auto; padding-right: 10px;">
          ${worldbookNames
            .map(
              name => `
            <label style="display: block; margin: 5px 0; color: #e0e0e0;">
              <input type="radio" name="worldbook" value="${escapeHtml(name)}" style="margin-right: 8px;">
              ${escapeHtml(name)}
            </label>
          `,
            )
            .join('')}
        </div>
        <div style="text-align: right;">
          <button id="cancelWorldbook" style="
            background: #666;
            color: white;
            border: none;
            padding: 8px 16px;
            border-radius: 4px;
            margin-right: 10px;
            cursor: pointer;
          ">取消</button>
          <button id="confirmWorldbook" style="
            background: #546B83;
            color: white;
            border: none;
            padding: 8px 16px;
            border-radius: 4px;
            cursor: pointer;
          ">确定</button>
        </div>
      </div>
    `);

    const overlay = $(`
      <div id="${overlayId}" style="
        position: fixed;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        background: rgba(0, 0, 0, 0.5);
        z-index: ${zIndex - 1};
      "></div>
    `);

    hostBody.append(overlay).append(dialog);

    dialog.find('#cancelWorldbook').on('click', () => {
      overlay.remove();
      dialog.remove();
      resolve(null);
    });

    dialog.find('#confirmWorldbook').on('click', () => {
      const selected = dialog.find('input[name="worldbook"]:checked').val() as string;
      overlay.remove();
      dialog.remove();
      resolve(selected || null);
    });

    overlay.on('click', () => {
      overlay.remove();
      dialog.remove();
      resolve(null);
    });

    dialog.find('input[name="worldbook"]:first').prop('checked', true);
  });
};

// 显示调试面板
