    });

    // 同步数据
    parentDoc.getElementById('syncData')?.addEventListener('click', () => {
      log('🔄 开始同步数据...');
      try {
        if ((window as any).syncAutoSummaryData) {
          (window as any).syncAutoSummaryData();
          log('✅ 同步函数已执行，请查看控制台输出');
