          log('❌ 同步函数不可用');
        }
      } catch (error) {
        log('❌ 同步失败: ' + (error as Error).message);
      }
    });

    // 检查楼层
    parentDoc.getElementById('checkFloor')?.addEventListener('click', () => {
      log('🔍 开始检查楼层...');
      try {
        if ((window as any).checkCurrentFloor) {
          (window as any).checkCurrentFloor();
          log('✅ 楼层检查函数已执行，请查看控制台输出');
