<template>
  <div style="font-family: -apple-system, BlinkMacSystemFont, 'SF Pro Text', 'PingFang SC', 'Microsoft YaHei', sans-serif">
    <!-- 顶部返回栏 -->
    <div
      style="
        display: flex;
        align-items: center;
        gap: 10px;
        padding: 6px 2px 16px;
        margin-bottom: 4px;
        border-bottom: 0.5px solid rgba(255,255,255,0.08);
      "
    >
      <button
        style="
          display: inline-flex;
          align-items: center;
          gap: 5px;
          background: none;
          border: none;
          color: #0a84ff;
          font-size: 15px;
          font-weight: 500;
          cursor: pointer;
          padding: 4px 6px;
          font-family: inherit;
        "
        @click="$emit('back')"
      >
        <i class="fa-solid fa-chevron-left" style="font-size: 13px"></i> 工具箱
      </button>
      <span style="flex: 1; text-align: center; color: #f5f5f7; font-size: 15px; font-weight: 600; display: flex; align-items: center; justify-content: center; gap: 8px">
        <i v-if="def" :class="def.icon" :style="{ color: def.color, fontSize: '14px' }"></i>
        {{ title }}
      </span>
      <span style="width: 64px"></span>
    </div>

    <!-- 工具本体 -->
    <div style="padding-top: 14px">
      <KeepAlive :max="5">
        <component :is="resolvedComponent" v-if="resolvedComponent" :key="toolId" :available-worldbooks="availableWorldbooks" />
      </KeepAlive>
      <div v-if="!resolvedComponent" style="text-align: center; padding: 50px 20px; color: rgba(235,235,245,0.55)">
        <i class="fa-solid fa-triangle-exclamation" style="font-size: 36px; color: #ff9f0a; margin-bottom: 12px"></i>
        <div>工具加载失败</div>
        <button
          style="margin-top: 14px; padding: 8px 18px; background: #0a84ff; border: none; border-radius: 999px; color: #fff; font-size: 13px; cursor: pointer"
          @click="$emit('back')"
        >
          返回工具箱
        </button>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { computed, onMounted } from 'vue';
import { useI18n } from '../../i18n';
import { getToolDefinition, resolveToolComponent } from './toolRegistry';
import { useWorldbook } from './useToolsCommon';

const props = defineProps<{ toolId: string }>();
defineEmits<{ (e: 'back'): void }>();

const { t } = useI18n();
const { availableWorldbooks, loadAvailableWorldbooks } = useWorldbook();
onMounted(loadAvailableWorldbooks);

const def = computed(() => getToolDefinition(props.toolId));
const resolvedComponent = computed(() => resolveToolComponent(props.toolId));
const title = computed(() => {
  const d = def.value;
  if (!d) return '工具';
  if (d.i18nKey) {
    const translated = t(d.i18nKey);
    if (translated && translated !== d.i18nKey) return translated;
  }
  return d.label;
});
</script>
