<script setup lang="ts">
import { computed, onMounted, onUnmounted, ref, watch } from 'vue';
import { useI18n } from '../i18n';
import CatIcon from './CatIcon.vue';
import { minimizeMemoryPanel } from '../浮动面板';
import ErrorBoundary from './ErrorBoundary.vue';
import GreetingsTab from './GreetingsTab.vue';
import HelpTab from './HelpTab.vue';
import MvuBetaTab from './MvuBetaTab.vue';
import PreferencesTab from './PreferencesTab.vue';
import ProjectManager from './ProjectManager.vue';
import RegexUIGenerator from './RegexUIGenerator.vue';
import SettingsTab from './SettingsTab.vue';
import StatusBarGenerator from './StatusBarGenerator.vue';
import SummaryTab from './SummaryTab.vue';
import TableTab from './TableTab.vue';
import TokenStatsTab from './TokenStatsTab.vue';
import ToolsTab from './ToolsTab.vue';

// 国际化
const { t } = useI18n();

// 6个主标签配置（全量）
const allMainTabs = [
  { key: 'settings', label: '设置', icon: 'fa-solid fa-cog' },
  { key: 'memory', label: '记忆管理', icon: 'fa-solid fa-brain' },
  { key: 'statusbar', label: '状态栏', icon: 'fa-solid fa-chart-bar' },
  { key: 'toolbox', label: '工具箱', icon: 'fa-solid fa-toolbox' },
  { key: 'mvu', label: 'MVU', icon: 'fa-solid fa-flask' },
  { key: 'help', label: '帮助', icon: 'fa-solid fa-question-circle' },
];

// 模块显隐偏好（在「界面偏好」中可关闭某些模块）。settings 始终可见，不允许关闭。
const moduleVisibility = ref<Record<string, boolean>>({});

const loadModuleVisibility = () => {
  try {
    const saved = localStorage.getItem('maomaomz_preferences');
    if (saved) {
      const prefs = JSON.parse(saved);
      if (prefs.moduleVisibility && typeof prefs.moduleVisibility === 'object') {
        moduleVisibility.value = prefs.moduleVisibility;
      }
    }
  } catch (e) {
    console.warn('读取模块显隐偏好失败:', e);
  }
};

// 实际展示的主标签（过滤掉被用户关闭的模块；settings 永远保留）
const mainTabs = computed(() =>
  allMainTabs.filter(tab => tab.key === 'settings' || moduleVisibility.value[tab.key] !== false),
);

// 子标签配置（按主标签分组）
const subTabsConfig: Record<string, Array<{ key: string; label: string; icon: string }>> = {
  settings: [
    { key: 'settings', label: 'AI 设置', icon: 'fa-solid fa-cog' },
    { key: 'preferences', label: '界面偏好', icon: 'fa-solid fa-sliders' },
  ],
  memory: [
    { key: 'summary', label: '总结历史', icon: 'fa-solid fa-list' },
    { key: 'table', label: '表格', icon: 'fa-solid fa-table' },
    { key: 'token', label: 'Token统计', icon: 'fa-solid fa-chart-pie' },
  ],
  statusbar: [
    { key: 'status', label: '快速生成', icon: 'fa-solid fa-bolt' },
    { key: 'regex', label: '翻页状态栏', icon: 'fa-solid fa-book-open' },
    { key: 'project', label: '前端项目', icon: 'fa-solid fa-laptop-code' },
  ],
  toolbox: [
    { key: 'greetings', label: '开场白', icon: 'fa-solid fa-comments' },
    { key: 'tools', label: '工具模板', icon: 'fa-solid fa-tools' },
  ],
  // mvu 和 help 没有子标签
};

// 当前选中的主标签
const activeMainTab = ref<'settings' | 'memory' | 'statusbar' | 'toolbox' | 'mvu' | 'help'>('settings');

// 当前选中的组件 key（实际渲染的组件）
const activeTab = ref<
  | 'settings'
  | 'preferences'
  | 'summary'
  | 'table'
  | 'greetings'
  | 'status'
  | 'regex'
  | 'project'
  | 'tools'
  | 'token'
  | 'mvu'
  | 'help'
>('settings');

// 当前主标签对应的子标签列表
const currentSubTabs = computed(() => subTabsConfig[activeMainTab.value] || []);

// 切换主标签
const switchMainTab = (tabKey: string) => {
  activeMainTab.value = tabKey as any;
  // 切换主标签时，自动选中第一个子标签（如果有）
  const subs = subTabsConfig[tabKey];
  if (subs && subs.length > 0) {
    activeTab.value = subs[0].key as any;
  } else {
    // 没有子标签的（mvu, help），直接用主标签 key
    activeTab.value = tabKey as any;
  }
};

// 若当前激活的主标签被用户隐藏，则回退到「设置」
watch(mainTabs, list => {
  if (!list.some(tab => tab.key === activeMainTab.value)) {
    switchMainTab('settings');
  }
});

// 标签页配置（兼容移动端，保留完整列表）
const tabs = computed(() => [
  { key: 'settings', label: t('tab_settings'), icon: 'fa-solid fa-cog' },
  { key: 'preferences', label: t('tab_preferences'), icon: 'fa-solid fa-sliders' },
  { key: 'summary', label: t('tab_summary_history'), icon: 'fa-solid fa-list' },
  { key: 'table', label: t('tab_table'), icon: 'fa-solid fa-table' },
  { key: 'greetings', label: t('tab_greetings'), icon: 'fa-solid fa-comments' },
  { key: 'regex', label: t('tab_status_bar_page'), icon: 'fa-solid fa-book-open' },
  { key: 'status', label: t('tab_status_bar_gen'), icon: 'fa-solid fa-chart-bar' },
  { key: 'project', label: t('tab_frontend_project'), icon: 'fa-solid fa-laptop-code' },
  { key: 'tools', label: t('tab_tools_template'), icon: 'fa-solid fa-tools' },
  { key: 'token', label: t('tab_token_stats'), icon: 'fa-solid fa-chart-pie' },
  { key: 'mvu', label: 'MVU Beta', icon: 'fa-solid fa-flask' },
  { key: 'help', label: t('tab_help'), icon: 'fa-solid fa-question-circle' },
]);

// 仅用于 UI 的移动端检测，不影响业务逻辑
const isMobile = ref(false);

// 移动端标签菜单展开状态
const isMobileMenuOpen = ref(false);

const updateIsMobile = () => {
  isMobile.value = window.innerWidth <= 768;
};

// 初始化时加载并应用偏好设置（确保背景图片等设置在面板加载时就生效）
const loadAndApplyPreferences = () => {
  try {
    const saved = localStorage.getItem('maomaomz_preferences');
    if (saved) {
      const preferences = JSON.parse(saved);
      // 应用主题色
      if (preferences.themeColor) {
        document.documentElement.style.setProperty('--maomaomz-theme-color', preferences.themeColor);
      }
      // 应用背景图片
      document.documentElement.style.setProperty(
        '--maomaomz-bg-image',
        preferences.backgroundImage ? `url(${preferences.backgroundImage})` : 'none',
      );
      // 应用背景透明度
      const opacity = preferences.backgroundOpacity ?? 30;
      document.documentElement.style.setProperty('--maomaomz-bg-opacity', (opacity / 100).toString());
      console.log('🖼️ MainPanel: 背景设置已初始化, 透明度:', opacity + '%');

      // 浅色模式已移除：确保始终深色
      const panelEl = document.getElementById('memoryManagementPanel');
      panelEl?.classList.remove('maomaomz-light');
    }
  } catch (error) {
    console.error('❌ MainPanel: 加载偏好设置失败:', error);
  }
};

// 注入最终外观样式。这个 style 在运行时最后插入，必须承担最高优先级的 iOS 外观覆盖。
