      color: #ffffff !important;
      -webkit-text-fill-color: #ffffff !important;
    }

    #memoryManagementPanel .toggle-switch,
    #memoryManagementPanel label[style*="width: 56px"] {
      transform: scale(0.92);
    }

    /* iOS 风格滑动开关（运行时注入，确保随 JS 更新，避免 style.css 缓存） */
