onMounted(() => {
  updateIsMobile();
  window.addEventListener('resize', updateIsMobile);
  // 注入玻璃效果样式
  injectGlassStyles();
  // 初始化偏好设置
  loadAndApplyPreferences();
  // 加载模块显隐偏好
  loadModuleVisibility();
  // 偏好变更时实时刷新模块显隐
  window.addEventListener('maomaomz-preferences-updated', loadModuleVisibility);
});

onUnmounted(() => {
  window.removeEventListener('resize', updateIsMobile);
  window.removeEventListener('maomaomz-preferences-updated', loadModuleVisibility);
});

// 组件映射
const componentMap = {
  settings: SettingsTab,
  preferences: PreferencesTab,
  summary: SummaryTab,
  table: TableTab,
  greetings: GreetingsTab,
  status: StatusBarGenerator,
  regex: RegexUIGenerator,
  project: ProjectManager,
  tools: ToolsTab,
  token: TokenStatsTab,
  mvu: MvuBetaTab,
  help: HelpTab,
};

// 当前组件
const currentComponent = computed(() => componentMap[activeTab.value]);

// 组件属性
const componentProps = computed(() => ({
  activeTab: activeTab.value,
}));

// 切换标签页
const switchTab = (tabKey: string) => {
  console.log('切换标签页:', tabKey);
  activeTab.value = tabKey as any;
};

// 当前标签信息（用于移动端头部展示）
const currentTab = computed(() => {
  return tabs.value.find(tab => tab.key === activeTab.value) ?? tabs.value[0];
});

// 切换移动端菜单展开状态
const toggleMobileMenu = () => {
  isMobileMenuOpen.value = !isMobileMenuOpen.value;
};

// 移动端点击标签：切换并收起菜单
const handleMobileTabClick = (tabKey: string) => {
  switchTab(tabKey);
  isMobileMenuOpen.value = false;
};

// 最小化面板
const minimizePanel = () => {
  minimizeMemoryPanel();
};

// 关闭面板
const closePanel = () => {
  $('#memoryManagementPanel').fadeOut(200);
};
