/**
 * 统一的世界书读取工具。
 *
 * 设计原则（重要）：
 * 所有"需要读取世界书"的功能，都应读取**当前生效的全部世界书的全部条目**，
 * 而不是只读某一本、或只读某一条。
 *
 * 这里会聚合：
 *  - 角色卡绑定的世界书（主世界书 primary + 附加世界书 additional）
 *  - 当前聊天文件绑定的世界书
 *  - 全局世界书（开启的那些）
 *
 * 然后读取每一本里的**全部条目**（默认跳过被禁用的条目），拼成纯文本供 AI 使用。
 */

import { preprocessContent } from './content-filter';

export interface WorldbookEntryLite {
  name: string;
  content: string;
  worldbook: string;
}

export interface CollectWorldbookOptions {
  /** 是否包含全局世界书，默认 true */
  includeGlobal?: boolean;
  /** 是否包含角色卡绑定的世界书，默认 true */
  includeChar?: boolean;
  /** 是否包含当前聊天绑定的世界书，默认 true */
  includeChat?: boolean;
  /** 是否跳过被禁用的条目，默认 true */
  skipDisabled?: boolean;
  /** 是否对内容做敏感词预处理，默认 true */
  filterContent?: boolean;
}

/**
 * 收集"当前生效的全部世界书"的名称（去重）。
 */
export function collectActiveWorldbookNames(options: CollectWorldbookOptions = {}): string[] {
  const { includeGlobal = true, includeChar = true, includeChat = true } = options;
  const TH = (window as any).TavernHelper;
  const names: string[] = [];

  if (!TH) return names;

  // 1) 角色卡绑定（主 + 附加）
  if (includeChar) {
    try {
      if (typeof TH.getCharWorldbookNames === 'function') {
        const cw = TH.getCharWorldbookNames('current');
        if (cw?.primary) names.push(cw.primary);
        if (Array.isArray(cw?.additional)) names.push(...cw.additional);
      } else if (typeof TH.getCharLorebooks === 'function') {
        // 兼容旧 API
        const cw = TH.getCharLorebooks({ type: 'all' });
        if (cw?.primary) names.push(cw.primary);
        if (Array.isArray(cw?.additional)) names.push(...cw.additional);
      }
    } catch (e) {
      console.warn('读取角色卡绑定世界书失败:', e);
    }
  }

  // 2) 当前聊天绑定
  if (includeChat) {
    try {
      if (typeof TH.getChatWorldbookName === 'function') {
        const chatWb = TH.getChatWorldbookName('current');
        if (chatWb) names.push(chatWb);
      }
    } catch (e) {
      console.warn('读取聊天绑定世界书失败:', e);
    }
  }

  // 3) 全局世界书
  if (includeGlobal) {
    try {
      if (typeof TH.getGlobalWorldbookNames === 'function') {
        const globals = TH.getGlobalWorldbookNames() || [];
        if (Array.isArray(globals)) names.push(...globals);
      }
    } catch (e) {
      console.warn('读取全局世界书失败:', e);
    }
  }

  // 去重并过滤空值
  const seen = new Set<string>();
  const result: string[] = [];
  for (const n of names) {
    if (!n || seen.has(n)) continue;
    seen.add(n);
    result.push(n);
  }
  return result;
}

/**
 * 读取某一本世界书的全部条目（兼容新旧 API）。
 */
async function readWorldbookEntries(worldbookName: string): Promise<any[]> {
  const TH = (window as any).TavernHelper;
  if (!TH || !worldbookName) return [];
  try {
    if (typeof TH.getWorldbook === 'function') {
      return (await TH.getWorldbook(worldbookName)) || [];
    }
    if (typeof TH.getWorldbookEntries === 'function') {
      return TH.getWorldbookEntries(worldbookName) || [];
    }
    if (typeof TH.getLorebookEntries === 'function') {
      return (await TH.getLorebookEntries(worldbookName)) || [];
    }
  } catch (e) {
    console.warn(`读取世界书「${worldbookName}」条目失败:`, e);
  }
  return [];
}

/**
 * 收集"当前生效的全部世界书的全部条目"（结构化）。
 */
export async function collectAllWorldbookEntries(
  options: CollectWorldbookOptions = {},
): Promise<WorldbookEntryLite[]> {
  const { skipDisabled = true, filterContent = true } = options;
  const names = collectActiveWorldbookNames(options);
  const result: WorldbookEntryLite[] = [];

  for (const name of names) {
    const entries = await readWorldbookEntries(name);
    for (const e of entries) {
      if (!e) continue;
      if (skipDisabled && e.enabled === false) continue;
      const content = e.content ?? e.value ?? '';
      if (!content) continue;
      result.push({
        name: e.name || e.comment || '条目',
        content: filterContent ? preprocessContent(String(content)) : String(content),
        worldbook: name,
      });
    }
  }

  return result;
}

/**
 * 收集"当前生效的全部世界书的全部条目"，并拼成可直接喂给 AI 的纯文本。
 *
 * @param maxLength 文本最大长度（字符数），超出截断，默认 8000
 */
export async function collectWorldbookText(
  options: CollectWorldbookOptions & { maxLength?: number } = {},
): Promise<string> {
  const { maxLength = 8000 } = options;
  const entries = await collectAllWorldbookEntries(options);
  if (entries.length === 0) return '';
  const text = entries.map(e => `【${e.name}】${e.content}`).join('\n');
  return text.length > maxLength ? text.slice(0, maxLength) : text;
}
