<template>
  <div
    class="tools-tab"
    style="padding: 20px 22px !important; background: transparent !important; height: 100%; overflow-y: auto; font-family: -apple-system, BlinkMacSystemFont, 'SF Pro Text', 'PingFang SC', 'Microsoft YaHei', sans-serif"
  >
    <!-- 使用指南（仅首页显示） -->
    <QuickGuide
      v-if="currentView === 'home'"
      storage-key="maomaomz_tools_guide_hidden"
      title="AI 工具箱使用指南"
      icon="fa-solid fa-toolbox"
      theme="purple"
      :steps="[
        { title: '选择工具', desc: '点击进入你需要的工具' },
        { title: '输入内容', desc: '粘贴或输入要处理的文本' },
        { title: 'AI 处理', desc: '点击按钮让 AI 帮你处理' },
      ]"
    />

    <ToolboxHome
      v-if="currentView === 'home'"
      :groups="groups"
      :active-group="activeGroup"
      :search-query="searchQuery"
      @select-tool="selectTool"
      @update:active-group="onUpdateGroup"
      @update:search-query="searchQuery = $event"
    />
    <ToolDetail v-else :tool-id="currentView" @back="backToHome" />
  </div>
</template>

<script setup lang="ts">
import { onMounted, ref, computed } from 'vue';
import { getScriptIdSafe } from '../utils';
import { loadToolsDataFromStorage, saveToolsDataToStorage } from './tools/toolsStorageService';
import { buildToolGroups, getToolDefinition, type ToolGroupKey } from './tools/toolRegistry';
import ToolboxHome from './tools/ToolboxHome.vue';
import ToolDetail from './tools/ToolDetail.vue';
import QuickGuide from './QuickGuide.vue';

const groups = computed(() => buildToolGroups());

const currentView = ref<'home' | string>('home');
const activeGroup = ref<ToolGroupKey | 'all'>('all');
const searchQuery = ref('');

const scriptId = getScriptIdSafe() || 'maomaomz_extension_v1';

interface ToolsViewPersisted {
  tools_lastView?: string;
  tools_lastGroup?: ToolGroupKey | 'all';
  [key: string]: any;
}

function persist() {
  try {
    const existing = loadToolsDataFromStorage<ToolsViewPersisted>(scriptId, {});
    saveToolsDataToStorage(scriptId, {
      ...existing,
      tools_lastView: currentView.value,
      tools_lastGroup: activeGroup.value,
    });
  } catch {
    /* ignore */
  }
}

function selectTool(id: string) {
  if (!getToolDefinition(id)) return;
  currentView.value = id;
  persist();
  try {
    const el = document.querySelector('.tools-tab');
    if (el) el.scrollTop = 0;
  } catch {
    /* ignore */
  }
}

function backToHome() {
  currentView.value = 'home';
  persist();
}

function onUpdateGroup(key: ToolGroupKey | 'all') {
  activeGroup.value = key;
  persist();
}

onMounted(() => {
  try {
    const saved = loadToolsDataFromStorage<ToolsViewPersisted>(scriptId, {});
    // 校验上次视图仍有效，否则回退首页
    const lastView = saved.tools_lastView;
    if (lastView && lastView !== 'home' && getToolDefinition(lastView)) {
      currentView.value = lastView;
    } else {
      currentView.value = 'home';
    }
    if (saved.tools_lastGroup) activeGroup.value = saved.tools_lastGroup;
  } catch {
    currentView.value = 'home';
  }
});
</script>
